import { randomBytes } from 'crypto';
import bcrypt from 'bcryptjs';
import { SignJWT, jwtVerify } from 'jose';
import { cookies } from 'next/headers';
import { env } from './env';
import { clearRateLimit as clearScopedRateLimit, rateLimit } from './rate-limit';
import {
  createAdminSessionRecord,
  deleteAdminSessionByToken,
  findAdminSessionByToken,
} from './admin-compat';

function getJwtSecret() {
  const secret = env.JWT_SECRET || (env.NODE_ENV === 'production' ? undefined : 'development-only-secret-change-before-production');

  if (!secret) {
    throw new Error('JWT_SECRET must be configured in production');
  }

  return new TextEncoder().encode(secret);
}

const SESSION_DURATION = 60 * 60 * 24 * 7; // 7 days
const JWT_ISSUER = 'douglasmitchell.info';
const JWT_AUDIENCE = 'admin-portal';

export interface Session {
  id: string;
  userId: string;
  email: string;
  name: string;
  role: 'admin' | 'editor';
  expiresAt: Date;
}

// Hash password with bcrypt
export async function hashPassword(password: string): Promise<string> {
  return bcrypt.hash(password, 12);
}

// Verify password
export async function verifyPassword(password: string, hashedPassword: string): Promise<boolean> {
  return bcrypt.compare(password, hashedPassword);
}

// Create JWT token
export async function createToken(payload: object): Promise<string> {
  return new SignJWT({ ...payload })
    .setProtectedHeader({ alg: 'HS256' })
    .setIssuer(JWT_ISSUER)
    .setAudience(JWT_AUDIENCE)
    .setIssuedAt()
    .setExpirationTime('7d')
    .sign(getJwtSecret());
}

// Verify JWT token
export async function verifyToken(token: string): Promise<Session | null> {
  try {
    const { payload } = await jwtVerify(token, getJwtSecret(), {
      issuer: JWT_ISSUER,
      audience: JWT_AUDIENCE,
    });
    return payload as unknown as Session;
  } catch {
    return null;
  }
}

// Create session
export async function createSession(
  userId: string,
  email: string,
  name: string,
  options?: {
    ipAddress?: string;
    userAgent?: string;
  }
): Promise<string> {
  const token = await createToken({
    userId,
    email,
    name,
    role: 'admin',
    expiresAt: new Date(Date.now() + SESSION_DURATION * 1000),
  });

  await createAdminSessionRecord({
    token,
    userId,
    expiresAt: new Date(Date.now() + SESSION_DURATION * 1000),
    ipAddress: options?.ipAddress,
    userAgent: options?.userAgent,
  });

  return token;
}

// Get current session from cookies
export async function getSession(): Promise<Session | null> {
  const cookieStore = await cookies();
  const token = cookieStore.get('admin-session')?.value;

  if (!token) return null;

  const session = await verifyToken(token);
  if (!session) return null;

  const persistedSession = await findAdminSessionByToken(token);

  if (!persistedSession || !persistedSession.isActive) {
    await deleteSession(token);
    return null;
  }

  // Check if session is expired
  if (new Date() > new Date(session.expiresAt) || new Date() > persistedSession.expiresAt) {
    await deleteSession(token);
    return null;
  }

  return {
    id: persistedSession.id,
    userId: persistedSession.userId,
    email: persistedSession.email,
    name: persistedSession.name || session.name,
    role: persistedSession.role as Session['role'],
    expiresAt: persistedSession.expiresAt,
  };
}

// Delete session
export async function deleteSession(token: string): Promise<void> {
  const cookieStore = await cookies();
  cookieStore.delete('admin-session');

  try {
    await deleteAdminSessionByToken(token);
  } catch {
    // Session might not exist in DB
  }
}

// Set session cookie
export async function setSessionCookie(token: string): Promise<void> {
  const cookieStore = await cookies();
  cookieStore.set('admin-session', token, {
    httpOnly: true,
    secure: env.NODE_ENV === 'production',
    sameSite: 'strict',
    maxAge: SESSION_DURATION,
    path: '/',
  });
}

// Rate limiting for login attempts
export async function checkRateLimit(identifier: string): Promise<boolean> {
  const result = await rateLimit(identifier, {
    limit: 5,
    windowMs: 15 * 60 * 1000,
    prefix: 'login',
  });

  return result.allowed;
}

// Clear rate limit
export function clearRateLimit(identifier: string): void {
  clearScopedRateLimit(identifier, 'login');
}

// Generate secure random token
export function generateSecureToken(length: number = 32): string {
  return randomBytes(length).toString('hex').slice(0, length);
}
import {
  generateRegistrationOptions,
  verifyRegistrationResponse,
  generateAuthenticationOptions,
  verifyAuthenticationResponse,
} from '@simplewebauthn/server';
import { env } from './env';

// Relying Party (RP) settings
export const rpID = env.PASSKEY_RP_ID || (env.NODE_ENV === 'production' ? 'douglasmitchell.info' : 'localhost');
export const rpName = env.PASSKEY_RP_NAME || 'Douglas Mitchell Portfolio';
export const origin = env.PASSKEY_EXPECTED_ORIGINS?.split(',') || [
  env.NEXT_PUBLIC_SITE_URL,
  'https://douglasmitchell.info',
  'https://www.douglasmitchell.info',
  'http://localhost:3000'
];

/**
 * Generate registration options for a new passkey
 */
export async function getRegistrationOptions(user: { id: string; email: string; name?: string | null }) {
  return generateRegistrationOptions({
    rpName,
    rpID,
    userID: Buffer.from(user.id),
    userName: user.email,
    userDisplayName: user.name || user.email,
    attestationType: 'none',
    authenticatorSelection: {
      residentKey: 'required',
      userVerification: 'preferred',
    },
  });
}

/**
 * Verify the registration response from the client
 */
export async function verifyRegistration(
  body: any,
  expectedChallenge: string
) {
  return verifyRegistrationResponse({
    response: body,
    expectedChallenge,
    expectedOrigin: origin,
    expectedRPID: rpID,
  });
}

/**
 * Generate authentication options for an existing passkey
 */
export async function getAuthenticationOptions(allowCredentials?: { id: string; transports?: any[] }[]) {
  return generateAuthenticationOptions({
    rpID,
    allowCredentials: allowCredentials?.map(cred => ({
      id: cred.id,
      transports: cred.transports,
    })),
    userVerification: 'preferred',
  });
}

/**
 * Verify the authentication response from the client
 */
export async function verifyAuthentication(
  body: any,
  expectedChallenge: string,
  credential: {
    id: string;
    publicKey: Uint8Array;
    counter: number;
  }
) {
  return verifyAuthenticationResponse({
    response: body,
    expectedChallenge,
    expectedOrigin: origin,
    expectedRPID: rpID,
    credential: {
      id: credential.id,
      publicKey: new Uint8Array(credential.publicKey),
      counter: credential.counter,
    },
  });
}

