import type { NextRequest } from 'next/server';
import { db } from '@/lib/db';
import { getClientIp, getUserAgent } from '@/lib/request';
import { getTableColumns, quoteIdentifier } from '@/lib/db-introspection';

interface LogActivityInput {
  action: string;
  resource: string;
  resourceId?: string;
  details?: Record<string, unknown>;
  userId?: string;
  request?: NextRequest;
}

export async function logActivity(input: LogActivityInput) {
  try {
    const columns = await getTableColumns('ActivityLog');
    if (columns.size === 0) {
      return;
    }

    const insertColumns = ['id', 'action', 'resource'];
    const values: unknown[] = [crypto.randomUUID(), input.action, input.resource];

    if (input.resourceId && columns.has('resourceId')) {
      insertColumns.push('resourceId');
      values.push(input.resourceId);
    }

    if (input.details && columns.has('details')) {
      insertColumns.push('details');
      values.push(JSON.stringify(input.details));
    }

    if (input.userId && columns.has('userId')) {
      insertColumns.push('userId');
      values.push(input.userId);
    }

    if (input.request && columns.has('ipAddress')) {
      insertColumns.push('ipAddress');
      values.push(getClientIp(input.request));
    }

    if (input.request && columns.has('userAgent')) {
      insertColumns.push('userAgent');
      values.push(getUserAgent(input.request));
    }

    if (columns.has('createdAt')) {
      insertColumns.push('createdAt');
      values.push(new Date());
    }

    const placeholders = insertColumns.map((_, index) => `$${index + 1}`).join(', ');
    const columnList = insertColumns.map(quoteIdentifier).join(', ');

    await db.$executeRawUnsafe(
      `INSERT INTO "ActivityLog" (${columnList}) VALUES (${placeholders})`,
      ...values
    );
  } catch {
    return;
  }
}
import { isRedisActive, redis } from '@/lib/redis';

export interface RateLimitOptions {
  limit: number;
  windowMs: number;
  prefix?: string;
}

export interface RateLimitState {
  count: number;
  resetAt: number;
}

export interface RateLimitResult {
  allowed: boolean;
  remaining: number;
  resetAt: number;
}

const rateLimitStore = new Map<string, RateLimitState>();

function createStoreKey(identifier: string, prefix = 'global') {
  return `${prefix}:${identifier}`;
}

// Simple garbage collection to prevent memory leaks from sustained DoS
function cleanupStore() {
  const now = Date.now();
  for (const [key, state] of rateLimitStore.entries()) {
    if (now > state.resetAt) {
      rateLimitStore.delete(key);
    }
  }
}

function rateLimitInMemory(identifier: string, options: RateLimitOptions): RateLimitResult {
  cleanupStore(); // Clear expired entries to prevent memory exhaustion

  const now = Date.now();
  const storeKey = createStoreKey(identifier, options.prefix);
  const existing = rateLimitStore.get(storeKey);

  if (!existing || now > existing.resetAt) {
    rateLimitStore.set(storeKey, {
      count: 1,
      resetAt: now + options.windowMs,
    });

    return {
      allowed: true,
      remaining: Math.max(options.limit - 1, 0),
      resetAt: now + options.windowMs,
    };
  }

  if (existing.count >= options.limit) {
    return {
      allowed: false,
      remaining: 0,
      resetAt: existing.resetAt,
    };
  }

  existing.count += 1;
  rateLimitStore.set(storeKey, existing);

  return {
    allowed: true,
    remaining: Math.max(options.limit - existing.count, 0),
    resetAt: existing.resetAt,
  };
}

async function rateLimitInRedis(identifier: string, options: RateLimitOptions): Promise<RateLimitResult> {
  const now = Date.now();
  const storeKey = createStoreKey(identifier, options.prefix);

  const count = await redis!.incr(storeKey);

  if (count === 1) {
    await redis!.pexpire(storeKey, options.windowMs);
  }

  let ttl = await redis!.pttl(storeKey);
  if (ttl < 0) {
    await redis!.pexpire(storeKey, options.windowMs);
    ttl = options.windowMs;
  }

  const resetAt = now + ttl;
  const allowed = count <= options.limit;

  return {
    allowed,
    remaining: allowed ? Math.max(options.limit - count, 0) : 0,
    resetAt,
  };
}

export async function rateLimit(identifier: string, options: RateLimitOptions): Promise<RateLimitResult> {
  if (!isRedisActive()) {
    return rateLimitInMemory(identifier, options);
  }

  try {
    return await rateLimitInRedis(identifier, options);
  } catch {
    return rateLimitInMemory(identifier, options);
  }
}

export function clearRateLimit(identifier: string, prefix = 'global') {
  rateLimitStore.delete(createStoreKey(identifier, prefix));
}
