      citations: [],
      suggestions: DEFAULT_SUGGESTIONS,
      refusal: false,
    };
  }

  if (isSensitiveQuestion(trimmedQuestion)) {
    return {
      answer:
        'I only answer public, non-sensitive questions. For outreach, use the secure contact form on the site.',
      citations: [{ label: 'Secure contact form', href: PUBLIC_CONTACT_HREF }],
      suggestions: DEFAULT_SUGGESTIONS,
      refusal: true,
    };
  }

  const [staticKnowledge, dynamicKnowledge] = await Promise.all([
    Promise.resolve(buildStaticKnowledge()),
    buildDynamicKnowledge(),
  ]);

  const knowledge = [...staticKnowledge, ...dynamicKnowledge];
  const queryTokens = tokenize(trimmedQuestion);
  const requestedKinds = detectRequestedKinds(trimmedQuestion, queryTokens);
  const rankedResults = knowledge
    .map((entry) => ({
      entry,
      score: scoreEntry(queryTokens, requestedKinds, entry),
    }))
    .filter((item) => item.score > 0)
    .sort((left, right) => right.score - left.score);
  const rankedEntries = rankedResults.map((item) => item.entry);

  const collectionKind = Array.from(requestedKinds).find((kind) =>
    wantsCollectionAnswer(trimmedQuestion, kind)
  );

  if (collectionKind) {
    const collectionEntries = rankedEntries.filter((entry) => entry.kind === collectionKind);
    if (collectionEntries.length > 0) {
      return {
        ...buildCollectionAnswer(collectionKind, collectionEntries),
        refusal: false,
      };
    }
  }

  const topEntries = rankedEntries.slice(0, 3);
  const isStrictTopicMode = options.strictTopicMode ?? true;
  const topScore = rankedResults[0]?.score ?? 0;

  if (isStrictTopicMode && (topEntries.length === 0 || topScore < 6)) {
    return {
      answer:
        'I only answer public questions about Douglas Mitchell’s published work, writing, projects, certifications, book, and operating philosophy.',
      citations: [{ label: 'Secure contact form', href: PUBLIC_CONTACT_HREF }],
      suggestions: DEFAULT_SUGGESTIONS,
      refusal: true,
    };
  }

  const answer = buildAnswer(topEntries);

  return {
    ...answer,
    refusal: false,
  };
}

import { NextRequest } from 'next/server';
import { z } from 'zod';
import { ApiHandler } from '@/lib/api-response';
import { getPublicAssistantSettings } from '@/lib/admin-operator';
import { answerPublicQuestion } from '@/lib/public-assistant';
import { rateLimit } from '@/lib/rate-limit';
import {
  getClientIp,
  isInvalidJsonBodyError,
  readJsonBody,
  validateTrustedOrigin,
} from '@/lib/request';

const publicAssistantSchema = z.object({
  question: z.string().trim().min(1).max(500),
});

export async function POST(request: NextRequest) {
  try {
    const originCheck = validateTrustedOrigin(request);
    if (!originCheck.allowed) {
      return ApiHandler.forbidden(originCheck.reason);
    }

    const settings = await getPublicAssistantSettings();
    if (!settings.enabled) {
      return ApiHandler.forbidden('Public knowledge assistant is disabled.');
    }

    const payload = publicAssistantSchema.safeParse(await readJsonBody(request));
    if (!payload.success) {
      return ApiHandler.error('A valid question is required.', 400, payload.error.flatten());
    }

    const clientIp = getClientIp(request);
    const limit = await rateLimit(clientIp, {
      limit: settings.maxQuestionsPerIp,
      windowMs: 24 * 60 * 60 * 1000,
      prefix: 'public-assistant',
    });

    if (!limit.allowed) {
      return ApiHandler.error('Daily question limit reached for this IP.', 429, {
        remaining: limit.remaining,
        resetAt: limit.resetAt,
      });
    }

    const reply = await answerPublicQuestion(payload.data.question, {
      strictTopicMode: settings.strictTopicMode,
    });

    return ApiHandler.success({
      answer: reply.refusal ? settings.refusalMessage : reply.answer,
      citations: reply.citations,
      suggestions: reply.suggestions,
      refusal: reply.refusal,
      remaining: limit.remaining,
      resetAt: limit.resetAt,
    });
  } catch (error) {
    if (isInvalidJsonBodyError(error)) {
      return ApiHandler.error('Request body must be valid JSON.', 400);
    }

    return ApiHandler.internalServerError('Failed to answer public question.', error);
  }
}

import { NextResponse } from 'next/server';

export type ApiErrorResponse = {
  success: false;
  error: string;
  details?: string | unknown;
};

export type ApiSuccessResponse<T = unknown> = {
  success: true;
  data?: T;
  message?: string;
} & (T extends Record<string, unknown> ? T : Record<string, unknown>);

export class ApiHandler {
  /**
   * Generates a standardized successful API response.
   */
  static success<T extends Record<string, unknown> | undefined = undefined>(
    data?: T,
    message?: string,
    status = 200
  ) {
    return NextResponse.json(
      { success: true, message, ...(data || {}) },
      { status }
    );
  }

  /**
   * Generates a standardized error API response.
   */
  static error(error: string, status = 400, details?: unknown) {
    const payload: ApiErrorResponse = { success: false, error };
    if (details) {
      payload.details = details instanceof Error ? details.message : details;
    }
    return NextResponse.json(payload, { status });
  }

  /**
   * Standardized 401 Unauthorized response.
   */
  static unauthorized(error = 'Unauthorized') {
    return this.error(error, 401);
  }

  /**
   * Standardized 403 Forbidden response.
   */
  static forbidden(error = 'Forbidden') {
    return this.error(error, 403);
  }

  /**
   * Standardized 404 Not Found response.
   */
  static notFound(error = 'Resource not found') {
    return this.error(error, 404);
  }

  /**
   * Standardized 500 Internal Server Error response.
   */
  static internalServerError(error = 'Internal server error', details?: unknown) {
    console.error(`[API Error] ${error}:`, details);
    return this.error(error, 500);
  }
}
import { createHash } from 'node:crypto';
import { isIP } from 'node:net';
import type { NextRequest } from 'next/server';
import { env } from '@/lib/env';

type RequestLike = Request | NextRequest;

export interface TrustedOriginResult {
  allowed: boolean;
  origin: string | null;
  reason: string;
}

export class InvalidJsonBodyError extends Error {
  constructor(message = 'Request body must be valid JSON.') {
    super(message);
    this.name = 'InvalidJsonBodyError';
  }
}

function normalizeOrigin(value: string | null | undefined) {
  if (!value) {
    return null;
  }

  try {
    return new URL(value).origin;
  } catch {
    return null;
  }
}

function getAllowedOrigins(request: RequestLike) {
  const origins = new Set<string>();

  const configuredSiteOrigin = normalizeOrigin(env.NEXT_PUBLIC_SITE_URL);
  if (configuredSiteOrigin) {
    origins.add(configuredSiteOrigin);
  }

  const requestOrigin = normalizeOrigin(request.url);
  if (requestOrigin) {
    origins.add(requestOrigin);
  }

  for (const value of env.PASSKEY_EXPECTED_ORIGINS?.split(',') ?? []) {
    const origin = normalizeOrigin(value.trim());
    if (origin) {
      origins.add(origin);
    }
  }

  if (env.NODE_ENV !== 'production') {
    origins.add('http://127.0.0.1:3000');
    origins.add('http://localhost:3000');
  }

  return origins;
}

function getOriginCandidate(request: RequestLike) {
  const origin = normalizeOrigin(request.headers.get('origin'));
  if (origin) {
    return origin;
  }

  return normalizeOrigin(request.headers.get('referer'));
}

export function validateTrustedOrigin(request: RequestLike): TrustedOriginResult {
  const allowedOrigins = getAllowedOrigins(request);
  const candidate = getOriginCandidate(request);
  const secFetchSite = request.headers.get('sec-fetch-site');

  if (candidate && allowedOrigins.has(candidate)) {
    return {
      allowed: true,
      origin: candidate,
      reason: 'Trusted request origin.',
    };
  }

  if (
    !candidate &&
    (secFetchSite === 'same-origin' || secFetchSite === 'same-site' || secFetchSite === 'none')
  ) {
    const requestOrigin = normalizeOrigin(request.url);
    if (requestOrigin && allowedOrigins.has(requestOrigin)) {
      return {
        allowed: true,
        origin: requestOrigin,
        reason: 'Trusted same-site request.',
      };
    }
  }

  if (secFetchSite === 'cross-site') {
    return {
      allowed: false,
      origin: candidate,
      reason: 'Cross-site requests are not allowed for this endpoint.',
    };
  }

  return {
    allowed: false,
    origin: candidate,
    reason: 'Untrusted request origin.',
  };
}

function buildAnonymousFingerprint(request: RequestLike) {
  const seed = [
    request.headers.get('user-agent') || 'unknown',
    request.headers.get('accept-language') || 'unknown',
    request.headers.get('host') || normalizeOrigin(request.url) || 'unknown',
  ].join('|');

  return `anonymous:${createHash('sha256').update(seed).digest('hex').slice(0, 16)}`;
}

export function getClientIp(request: RequestLike) {
  const candidates = [
    request.headers.get('x-vercel-forwarded-for'),
    request.headers.get('cf-connecting-ip'),
    request.headers.get('x-real-ip'),
    request.headers.get('x-forwarded-for'),
  ];

  for (const candidate of candidates) {
    if (!candidate) {
      continue;
    }

    const normalized = candidate.split(',')[0]?.trim();
    if (normalized && isIP(normalized)) {
      return normalized;
    }
  }

  return buildAnonymousFingerprint(request);
}

export function getUserAgent(request: RequestLike) {
  return request.headers.get('user-agent') || 'unknown';
}

export async function readJsonBody<T = unknown>(request: RequestLike) {
  try {
    return (await request.json()) as T;
  } catch {
    throw new InvalidJsonBodyError();
  }
}

export function isInvalidJsonBodyError(error: unknown): error is InvalidJsonBodyError {
  return error instanceof InvalidJsonBodyError;
}

