'use client';

import { useEffect, useRef, useCallback } from 'react';

interface Particle {
  char: string;
  x: number;
  y: number;
  opacity: number;
  speed: number;
  size: number;
}

interface AsciiParticlesProps {
  particleCount?: number;
  className?: string;
}

const ASCII_CHARS = '∙∘○●○∘∙┄┅┈┉╌╍═─│┌┐└┘├┤┬┴┼';
const MATRIX_CHARS = 'ｱｲｳｴｵｶｷｸｹｺｻｼｽｾｿﾀﾁﾂﾃﾄﾅﾆﾇﾈﾉﾊﾋﾌﾍﾎﾏﾐﾑﾒﾓﾔﾕﾖﾗﾘﾙﾚﾛﾜﾝ';

export function AsciiParticles({ particleCount = 50, className = '' }: AsciiParticlesProps) {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const particlesRef = useRef<Particle[]>([]);
  const animationRef = useRef<number | null>(null);
  const prefersReducedMotion = useRef(false);

  // Check for reduced motion preference
  useEffect(() => {
    prefersReducedMotion.current = window.matchMedia('(prefers-reduced-motion: reduce)').matches;
  }, []);

  const initParticles = useCallback((width: number, height: number) => {
    particlesRef.current = Array.from({ length: particleCount }, () => ({
      char: ASCII_CHARS[Math.floor(Math.random() * ASCII_CHARS.length)],
      x: Math.random() * width,
      y: Math.random() * height,
      opacity: Math.random() * 0.3 + 0.1,
      speed: Math.random() * 0.5 + 0.1,
      size: Math.random() * 12 + 10,
    }));
  }, [particleCount]);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const handleResize = () => {
      canvas.width = window.innerWidth;
      canvas.height = window.innerHeight;
      initParticles(canvas.width, canvas.height);
    };

    handleResize();
    window.addEventListener('resize', handleResize);

    if (prefersReducedMotion.current) {
      // Static render for reduced motion
      ctx.font = '14px monospace';
      ctx.fillStyle = 'currentColor';
      particlesRef.current.forEach(particle => {
        ctx.globalAlpha = particle.opacity;
        ctx.fillText(particle.char, particle.x, particle.y);
      });
      return () => window.removeEventListener('resize', handleResize);
    }

    const animate = () => {
      if (!ctx || !canvas) return;

      ctx.clearRect(0, 0, canvas.width, canvas.height);
      ctx.font = '14px monospace';
      ctx.fillStyle = 'currentColor';

      particlesRef.current.forEach(particle => {
        particle.y -= particle.speed;

        if (particle.y < -20) {
          particle.y = canvas.height + 20;
          particle.x = Math.random() * canvas.width;
          particle.char = ASCII_CHARS[Math.floor(Math.random() * ASCII_CHARS.length)];
        }

        ctx.globalAlpha = particle.opacity;
        ctx.fillText(particle.char, particle.x, particle.y);
      });

      animationRef.current = requestAnimationFrame(animate);
    };

    animate();

    return () => {
      window.removeEventListener('resize', handleResize);
      if (animationRef.current) {
        cancelAnimationFrame(animationRef.current);
      }

export async function getRecentActivityEntries(limit: number) {
  if (!(await hasTable('ActivityLog'))) {
    return [];
  }

  const activityColumns = await getTableColumns('ActivityLog');
  const canJoinUser =
    activityColumns.has('userId') &&
    (await hasTable('AdminUser')) &&
    (await getTableColumns('AdminUser')).has('id');
  const values: unknown[] = [limit];

  const rows = await db.$queryRawUnsafe<
    Array<{
      id: string;
      action: string;
      resource: string;
      resourceId: string | null;
      createdAt: Date;
      actor: string | null;
    }>
  >(
    canJoinUser
      ? `SELECT a."id",
                a."action",
                a."resource",
                a."resourceId",
                a."createdAt",
                COALESCE(u."name", u."email") AS actor
         FROM "ActivityLog" a
         LEFT JOIN "AdminUser" u
           ON u."id" = a."userId"
         ORDER BY a."createdAt" DESC
         LIMIT $1`
      : `SELECT "id",
                "action",
                "resource",
                "resourceId",
                "createdAt",
                NULL::text AS actor
         FROM "ActivityLog"
         ORDER BY "createdAt" DESC
         LIMIT $1`,
    ...values
  );

  return rows;
}

