              {isMobileMenuOpen ? (
                <X className="h-4 w-4" />
              ) : (
                <Menu className="h-4 w-4" />
              )}
            </Button>

            {/* CTA - Desktop / Mobile Square */}
            <a
              href="#contact"
              className="cta-button text-sm p-2 sm:px-6 sm:py-3"
