export const getAdminAnalyticsData = cache(async () => {
  const fallback = {
    totalPageViews: 0,
    uniqueSessions: 0,
    contactSubmissions: 0,
    newsletterSubscribers: 0,
    topPages: [] as Array<{ path: string; views: number }>,
    pageViewSeries: [] as Array<{ date: string; views: number }>,
  };

  const [contactSubmissions, newsletterSubscribers] = await Promise.all([
    countContactSubmissions(),
    countNewsletterSubscribers(),
  ]);

  if (!(await hasTable('PageView'))) {
    return {
      ...fallback,
      contactSubmissions,
      newsletterSubscribers,
    };
  }

  return withFallback(async () => {
    const [totalPageViews, uniqueSessions, pageViews] = await Promise.all([
      db.pageView.count(),
      db.pageView.groupBy({ by: ['sessionId'] }),
      db.pageView.findMany({
        orderBy: { createdAt: 'desc' },
        take: 500,
      }),
    ]);

    const topPages = (Object.entries(
      pageViews.reduce<Record<string, number>>((acc, pageView) => {
        acc[pageView.path] = (acc[pageView.path] || 0) + 1;
        return acc;
      }, {})
    ) as Array<[string, number]>)
      .map(([path, views]) => ({ path, views }))
      .sort((a, b) => b.views - a.views)
      .slice(0, 5);

    const pageViewSeries = (Object.entries(
      pageViews.reduce<Record<string, number>>((acc, pageView) => {
        const key = pageView.createdAt.toISOString().slice(0, 10);
        acc[key] = (acc[key] || 0) + 1;
        return acc;
      }, {})
    ) as Array<[string, number]>)
      .map(([date, views]) => ({ date, views }))
      .sort((a, b) => a.date.localeCompare(b.date))
      .slice(-14);

    return {
      totalPageViews,
      uniqueSessions: uniqueSessions.length,
      contactSubmissions,
      newsletterSubscribers,
      topPages,
      pageViewSeries,
    };
  }, {
    ...fallback,
    contactSubmissions,
    newsletterSubscribers,
  });
});

export const getAdminSecurityData = cache(async () => {
  const fallback = {
    activeSessions: 0,
    passkeysRegistered: 0,
    adminUsers: 0,
    recentSessions: [] as Array<{
      id: string;
      email: string;
      lastSeen: string;
      ipAddress: string;
      userAgent: string;
    }>,
  };

  const legacySummary = await getAdminSecuritySummary();

  if (!(await hasTables(['AdminUser', 'PasskeyCredential', 'Session'])) && !legacySummary) {
    return fallback;
  }

  if (legacySummary) {
    return {
      activeSessions: legacySummary.activeSessions,
      passkeysRegistered: legacySummary.passkeysRegistered,
      adminUsers: legacySummary.adminUsers,
      recentSessions: legacySummary.recentSessions.map((session) => ({
        id: session.id,
        email: session.email,
        lastSeen: formatDistanceToNowStrict(session.createdAt, { addSuffix: true }),
        ipAddress: session.ipAddress || 'unknown',
        userAgent: session.userAgent || 'unknown',
      })),
    };
  }

  return withFallback(async () => {
    const [activeSessions, passkeysRegistered, adminUsers, recentSessions] = await Promise.all([
      db.session.count({ where: { expiresAt: { gt: new Date() } } }),
      db.passkeyCredential.count(),
      db.adminUser.count({ where: { isActive: true } }),
      db.session.findMany({
        where: { expiresAt: { gt: new Date() } },
        orderBy: { createdAt: 'desc' },
        take: 6,
        include: {
          user: {
            select: {
              email: true,
            },
          },
        },
      }),
    ]);

    return {
      activeSessions,
      passkeysRegistered,
      adminUsers,
      recentSessions: recentSessions.map((session) => ({
        id: session.id,
        email: session.user.email,
        lastSeen: formatDistanceToNowStrict(session.createdAt, { addSuffix: true }),
        ipAddress: session.ipAddress || 'unknown',
        userAgent: session.userAgent || 'unknown',
      })),
    };
  }, fallback);
});

export const getUserPasskeys = cache(async (userId: string) => {
  return withFallback(async () => {
    const legacyPasskeys = await getAdminPasskeysForUser(userId);
    const supportsCurrentPasskeyShape = await hasColumns('PasskeyCredential', ['userId', 'credentialId']);

    if (legacyPasskeys.length > 0 || !supportsCurrentPasskeyShape) {
      return legacyPasskeys.map((passkey) => ({
        id: passkey.id,
        credentialId: passkey.credentialId,
        deviceName: passkey.deviceName,
        createdAt: passkey.createdAt,
        lastUsedAt: passkey.lastUsedAt,
      }));
    }

    if (!(await hasTables(['PasskeyCredential']))) {
      return [];
    }

    return await db.passkeyCredential.findMany({
      where: { userId },
      orderBy: { createdAt: 'desc' },
      select: {
        id: true,
        credentialId: true,
        deviceName: true,
        createdAt: true,
        lastUsedAt: true,
      },
    });
  }, []);
});

