export const getAdminAnalyticsData = cache(async () => {
  const fallback = {
    totalPageViews: 0,
    uniqueSessions: 0,
    contactSubmissions: 0,
    newsletterSubscribers: 0,
    topPages: [] as Array<{ path: string; views: number; uniqueVisitors: number }>,
    pageViewSeries: [] as Array<{ date: string; views: number; sessions: number }>,
    browserBreakdown: [] as Array<{ browser: string; count: number }>,
    deviceBreakdown: [] as Array<{ device: string; count: number }>,
  };

  const [contactSubmissions, newsletterSubscribers] = await Promise.all([
    countContactSubmissions(),
    countNewsletterSubscribers(),
  ]);

  if (!(await hasTable('PageView'))) {
    return {
      ...fallback,
      contactSubmissions,
      newsletterSubscribers,
    };
  }

  return withFallback(async () => {
    // Get last 30 days of data for richer telemetry
    const thirtyDaysAgo = new Date();
    thirtyDaysAgo.setDate(thirtyDaysAgo.getDate() - 30);

    const [totalPageViews, uniqueSessionsResult, pageViews] = await Promise.all([
      db.pageView.count(),
      db.pageView.groupBy({ by: ['sessionId'] }),
      db.pageView.findMany({
        where: { createdAt: { gte: thirtyDaysAgo } },
        orderBy: { createdAt: 'desc' },
      }),
    ]);

    const topPages = (Object.entries(
      pageViews.reduce<Record<string, { views: number; sessions: Set<string> }>>((acc, pv) => {
        if (!acc[pv.path]) acc[pv.path] = { views: 0, sessions: new Set() };
        acc[pv.path].views++;
        acc[pv.path].sessions.add(pv.sessionId);
        return acc;
      }, {})
    ) as Array<[string, { views: number; sessions: Set<string> }]>)
      .map(([path, data]) => ({ 
        path, 
        views: data.views, 
        uniqueVisitors: data.sessions.size 
      }))
      .sort((a, b) => b.views - a.views)
      .slice(0, 10);

    const seriesMap = pageViews.reduce<Record<string, { views: number; sessions: Set<string> }>>((acc, pv) => {
      const key = pv.createdAt.toISOString().slice(0, 10);
      if (!acc[key]) acc[key] = { views: 0, sessions: new Set() };
      acc[key].views++;
      acc[key].sessions.add(pv.sessionId);
      return acc;
    }, {});

    const pageViewSeries = Object.entries(seriesMap)
      .map(([date, data]) => ({ 
        date, 
        views: data.views, 
        sessions: data.sessions.size 
      }))
      .sort((a, b) => a.date.localeCompare(b.date))
      .slice(-21);

    const browserBreakdown = (Object.entries(
      pageViews.reduce<Record<string, number>>((acc, pv) => {
        const ua = pv.userAgent || 'unknown';
        const browser = ua.includes('Firefox') ? 'Firefox' : 
                        ua.includes('Chrome') ? 'Chrome' : 
                        ua.includes('Safari') ? 'Safari' : 
                        ua.includes('Edge') ? 'Edge' : 'Other';
        acc[browser] = (acc[browser] || 0) + 1;
        return acc;
      }, {})
    ) as Array<[string, number]>)
      .map(([browser, count]) => ({ browser, count }))
      .sort((a, b) => b.count - a.count);

    return {
      totalPageViews,
      uniqueSessions: uniqueSessionsResult.length,
      contactSubmissions,
      newsletterSubscribers,
      topPages,
      pageViewSeries,
      browserBreakdown,
      deviceBreakdown: [], // Future enhancement
    };
  }, {
    ...fallback,
    contactSubmissions,
    newsletterSubscribers,
  });
});

export const getAdminSecurityData = cache(async () => {
  const fallback = {
    activeSessions: 0,
    passkeysRegistered: 0,
    adminUsers: 0,
    recentSessions: [] as Array<{
      id: string;
      email: string;
      lastSeen: string;
      ipAddress: string;
      userAgent: string;
    }>,
  };

  const legacySummary = await getAdminSecuritySummary();

  if (!(await hasTables(['AdminUser', 'PasskeyCredential', 'Session'])) && !legacySummary) {
    return fallback;
  }

  if (legacySummary) {
    return {
      activeSessions: legacySummary.activeSessions,
      passkeysRegistered: legacySummary.passkeysRegistered,
      adminUsers: legacySummary.adminUsers,
      recentSessions: legacySummary.recentSessions.map((session) => ({
        id: session.id,
        email: session.email,
        lastSeen: formatDistanceToNowStrict(session.createdAt, { addSuffix: true }),
        ipAddress: session.ipAddress || 'unknown',
        userAgent: session.userAgent || 'unknown',
      })),
    };
  }

  return withFallback(async () => {
    const [activeSessions, passkeysRegistered, adminUsers, recentSessions] = await Promise.all([
      db.session.count({ where: { expiresAt: { gt: new Date() } } }),
      db.passkeyCredential.count(),
      db.adminUser.count({ where: { isActive: true } }),
      db.session.findMany({
        where: { expiresAt: { gt: new Date() } },
        orderBy: { createdAt: 'desc' },
        take: 6,
        include: {
          user: {
            select: {
              email: true,
            },
          },
        },
      }),
    ]);

    return {
      activeSessions,
      passkeysRegistered,
      adminUsers,
      recentSessions: recentSessions.map((session) => ({
        id: session.id,
        email: session.user.email,
        lastSeen: formatDistanceToNowStrict(session.createdAt, { addSuffix: true }),
        ipAddress: session.ipAddress || 'unknown',
        userAgent: session.userAgent || 'unknown',
      })),
    };
  }, fallback);
});

export const getUserPasskeys = cache(async (userId: string) => {
  return withFallback(async () => {
    const legacyPasskeys = await getAdminPasskeysForUser(userId);
    const supportsCurrentPasskeyShape = await hasColumns('PasskeyCredential', ['userId', 'credentialId']);

    if (legacyPasskeys.length > 0 || !supportsCurrentPasskeyShape) {
      return legacyPasskeys.map((passkey) => ({
        id: passkey.id,
        credentialId: passkey.credentialId,
        deviceName: passkey.deviceName,
        createdAt: passkey.createdAt,
        lastUsedAt: passkey.lastUsedAt,
      }));
    }

    if (!(await hasTables(['PasskeyCredential']))) {
      return [];
    }

    return await db.passkeyCredential.findMany({
      where: { userId },
      orderBy: { createdAt: 'desc' },
      select: {
        id: true,
        credentialId: true,
        deviceName: true,
        createdAt: true,
        lastUsedAt: true,
      },
    });
  }, []);
});

