export default function ContentManagementPage() {
  const [activeTab, setActiveTab] = useState<ContentType>('article');
  const [searchQuery, setSearchQuery] = useState('');
  const [loading, setLoading] = useState(true);
  const [loadingEditor, setLoadingEditor] = useState(false);
  const [saving, setSaving] = useState(false);
  const [editorOpen, setEditorOpen] = useState(false);
  const [editorError, setEditorError] = useState<string | null>(null);
  const [banner, setBanner] = useState<string | null>(null);
  const [content, setContent] = useState<ContentApiResponse>({
    success: true,
    editable: false,
    source: 'fallback',
    warning: null,
    articles: [],
    projects: [],
    certifications: [],
    books: [],
  });
  const [editor, setEditor] = useState<EditorPayload | null>(null);

  useEffect(() => {
    const controller = new AbortController();

    const loadContent = async () => {
      try {
        const response = await fetch('/api/admin/content', { signal: controller.signal });
        const data = (await response.json()) as ContentApiResponse;
        if (response.ok) {
          setContent(data);
        } else {
          setBanner('Failed to load content inventory.');
        }
      } catch {
        setBanner('Failed to load content inventory.');
      } finally {
        setLoading(false);
      }
    };

    void loadContent();

    return () => controller.abort();
  }, []);

  const filteredContent = useMemo(() => {
    const normalizedQuery = searchQuery.toLowerCase();
    const matcher = (contentItem: ContentItem) =>
      contentItem.title.toLowerCase().includes(normalizedQuery) ||
      contentItem.slug.toLowerCase().includes(normalizedQuery);

    return {
      article: content.articles.filter(matcher),
      project: content.projects.filter(matcher),
      certification: content.certifications.filter(matcher),
      book: content.books.filter(matcher),
    };
  }, [content, searchQuery]);

  const openEditor = async (type: ContentType, contentItem: ContentItem) => {
    setLoadingEditor(true);
    setEditorError(null);
    setBanner(null);
    setEditorOpen(true);

    try {
      const response = await fetch(`/api/admin/content?type=${type}&id=${contentItem.id}`);
      const data = (await response.json()) as EditorApiResponse;

      if (!response.ok || !data.item) {
        throw new Error(data.error || 'Failed to load editor');
      }

      setEditor(data.item);
    } catch (error) {
      setEditor(null);
      setEditorError(error instanceof Error ? error.message : 'Failed to load editor.');
    } finally {
      setLoadingEditor(false);
    }
  };

  const handleFieldChange = (key: string, value: string | boolean) => {
    setEditor((current) => {
      if (!current) return current;
      return {
        ...current,
        fields: {
          ...current.fields,
          [key]: value,
        },
      };
    });
  };

  const refreshSnapshot = async () => {
    const response = await fetch('/api/admin/content');
    const data = (await response.json()) as ContentApiResponse;
    if (response.ok) {
      setContent(data);
    }
  };

  const handleSave = async () => {
    if (!editor) return;

    setSaving(true);
    setEditorError(null);

    try {
      const response = await fetch('/api/admin/content', {
        method: 'PATCH',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          type: editor.type,
          id: editor.id,
          fields: editor.fields,
        }),
      });
      const data = (await response.json()) as EditorApiResponse;

      if (!response.ok || !data.item) {
        throw new Error(data.error || 'Failed to save content item.');
      }

      setEditor(data.item);
      setBanner('Content updated successfully.');
      startTransition(() => {
        void refreshSnapshot();
      });
      setEditorOpen(false);
    } catch (error) {
      setEditorError(error instanceof Error ? error.message : 'Failed to save content item.');
    } finally {
      setSaving(false);
    }
  };

  return (
    <motion.div variants={container} initial="hidden" animate="show" className="space-y-6">
      <motion.div variants={item} className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold">Content Management</h1>
          <p className="text-muted-foreground">
            Review the editorial inventory, open previews, and update live metadata.
          </p>
        </div>
        <Button disabled={!content.editable}>
          <Plus className="mr-2 h-4 w-4" />
          {content.editable ? 'Use row editor' : 'Editing unavailable'}
        </Button>
      </motion.div>

      {content.warning || banner ? (
        <motion.div variants={item} className="rounded-xl border border-amber-500/30 bg-amber-500/10 px-4 py-3 text-sm text-amber-900 dark:text-amber-100">
          {banner || content.warning}
        </motion.div>
      ) : null}

      <motion.div variants={item} className="flex gap-4">
        <div className="relative flex-1">
          <Search className="absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-muted-foreground" />
          <Input
            placeholder="Search content..."
            value={searchQuery}
            onChange={(event) => setSearchQuery(event.target.value)}
            className="pl-9"
          />
        </div>
        <Button variant="outline" disabled>
          <Filter className="mr-2 h-4 w-4" />
          Filter
        </Button>
      </motion.div>

      <motion.div variants={item}>
        <Tabs value={activeTab} onValueChange={(value) => setActiveTab(value as ContentType)}>
          <TabsList>
            <TabsTrigger value="article">
              <FileText className="mr-2 h-4 w-4" />
              Articles
            </TabsTrigger>
            <TabsTrigger value="project">
              <FolderOpen className="mr-2 h-4 w-4" />
              Projects
            </TabsTrigger>
            <TabsTrigger value="certification">
              <Award className="mr-2 h-4 w-4" />
              Certifications
            </TabsTrigger>
            <TabsTrigger value="book">
              <BookOpen className="mr-2 h-4 w-4" />
              Books
            </TabsTrigger>
          </TabsList>

          <TabsContent value="article" className="mt-6">
            <Card>
              <CardHeader>
                <CardTitle>Articles ({filteredContent.article.length})</CardTitle>
              </CardHeader>
              <CardContent>
                {loading ? (
                  <p className="text-sm text-muted-foreground">Loading content…</p>
                ) : (
                  <ContentTable type="article" items={filteredContent.article} editable={content.editable} onEdit={openEditor} />
                )}
              </CardContent>
            </Card>
          </TabsContent>

          <TabsContent value="project" className="mt-6">
            <Card>
              <CardHeader>
                <CardTitle>Projects ({filteredContent.project.length})</CardTitle>
              </CardHeader>
              <CardContent>
                {loading ? (
                  <p className="text-sm text-muted-foreground">Loading content…</p>
                ) : (
                  <ContentTable type="project" items={filteredContent.project} editable={content.editable} onEdit={openEditor} />
                )}
              </CardContent>
            </Card>
          </TabsContent>

          <TabsContent value="certification" className="mt-6">
            <Card>
              <CardHeader>
                <CardTitle>Certifications ({filteredContent.certification.length})</CardTitle>
              </CardHeader>
              <CardContent>
                {loading ? (
                  <p className="text-sm text-muted-foreground">Loading content…</p>
                ) : (
                  <ContentTable type="certification" items={filteredContent.certification} editable={content.editable} onEdit={openEditor} />
                )}
              </CardContent>
            </Card>
          </TabsContent>

          <TabsContent value="book" className="mt-6">
            <Card>
              <CardHeader>
                <CardTitle>Books ({filteredContent.book.length})</CardTitle>
              </CardHeader>
              <CardContent>
                {loading ? (
                  <p className="text-sm text-muted-foreground">Loading content…</p>
                ) : (
                  <ContentTable type="book" items={filteredContent.book} editable={content.editable} onEdit={openEditor} />
                )}
              </CardContent>
            </Card>
          </TabsContent>
        </Tabs>
      </motion.div>

      <EditorDialog
        editor={editor}
        open={editorOpen}
        saving={saving}
        error={editorError}
        onOpenChange={(open) => {
          setEditorOpen(open);
          if (!open) {
            setEditorError(null);
          }
        }}
        onFieldChange={handleFieldChange}
        onSave={handleSave}
      />

      <Dialog open={loadingEditor} onOpenChange={() => undefined}>
        <DialogContent className="max-w-sm" showCloseButton={false}>
          <DialogHeader>
            <DialogTitle>Loading editor</DialogTitle>
            <DialogDescription>Preparing the content form.</DialogDescription>
          </DialogHeader>
          <div className="flex items-center gap-3 text-sm text-muted-foreground">
            <Loader2 className="h-4 w-4 animate-spin" />
            Fetching the latest content fields.
          </div>
        </DialogContent>
      </Dialog>
    </motion.div>
  );
}

resultDisplay.newContent:
'use client';

import Link from 'next/link';
import { startTransition, useEffect, useMemo, useState } from 'react';
import { motion } from 'framer-motion';
import {
  Award,
  BookOpen,
  Check,
  Edit,
  Eye,
  FileText,
  Filter,
  FolderOpen,
  Loader2,
  MoreHorizontal,
  Plus,
