import bcrypt from 'bcryptjs';
import { SignJWT, jwtVerify } from 'jose';
import { cookies } from 'next/headers';
import { env } from './env';
import { clearRateLimit as clearScopedRateLimit, rateLimit } from './rate-limit';
import {
  createAdminSessionRecord,
  deleteAdminSessionByToken,
  findAdminSessionByToken,
} from './admin-compat';

function getJwtSecret() {
  const secret = env.JWT_SECRET || (env.NODE_ENV === 'production' ? undefined : 'development-only-secret-change-before-production');

  if (!secret) {
    throw new Error('JWT_SECRET must be configured in production');
  }

  return new TextEncoder().encode(secret);
}

const SESSION_DURATION = 60 * 60 * 24 * 7; // 7 days
const JWT_ISSUER = 'douglasmitchell.info';
const JWT_AUDIENCE = 'admin-portal';

export interface Session {
  id: string;
  userId: string;
  email: string;
  name: string;
  role: 'admin' | 'editor';
  expiresAt: Date;
}

// Hash password with bcrypt
export async function hashPassword(password: string): Promise<string> {
  return bcrypt.hash(password, 12);
}

// Verify password
export async function verifyPassword(password: string, hashedPassword: string): Promise<boolean> {
  return bcrypt.compare(password, hashedPassword);
}

// Create JWT token
export async function createToken(payload: object): Promise<string> {
  return new SignJWT({ ...payload })
    .setProtectedHeader({ alg: 'HS256' })
    .setIssuer(JWT_ISSUER)
    .setAudience(JWT_AUDIENCE)
    .setIssuedAt()
    .setExpirationTime('7d')
    .sign(getJwtSecret());
}

// Verify JWT token
export async function verifyToken(token: string): Promise<Session | null> {
  try {
    const { payload } = await jwtVerify(token, getJwtSecret(), {
      issuer: JWT_ISSUER,
      audience: JWT_AUDIENCE,
    });
    return payload as unknown as Session;
  } catch {
    return null;
  }
}

// Create session
export async function createSession(
  userId: string,
  email: string,
  name: string,
  options?: {
    ipAddress?: string;
    userAgent?: string;
  }
): Promise<string> {
  const token = await createToken({
    userId,
    email,
    name,
    role: 'admin',
    expiresAt: new Date(Date.now() + SESSION_DURATION * 1000),
  });

  await createAdminSessionRecord({
    token,
    userId,
    expiresAt: new Date(Date.now() + SESSION_DURATION * 1000),
    ipAddress: options?.ipAddress,
    userAgent: options?.userAgent,
  });

  return token;
